      startDate: json["start_date"] as String?,
    );
  }
}

typedef SubjectAttribution = String;

class TaskItem {
  final bool completed;
  final String? completedAt;
  final String? conversationId;
  final String? createdAt;
  final String description;
  final String? dueAt;
  final String id;
  final String? updatedAt;

  const TaskItem(
      {required this.completed,
      this.completedAt,
      this.conversationId,
      this.createdAt,
      required this.description,
      this.dueAt,
      required this.id,
      this.updatedAt});

  factory TaskItem.fromJson(Map<String, dynamic> json) {
    return TaskItem(
      completed: json["completed"] as bool,
      completedAt: json["completed_at"] as String?,
      conversationId: json["conversation_id"] as String?,
      createdAt: json["created_at"] as String?,
      description: json["description"] as String,
      dueAt: json["due_at"] as String?,
      id: json["id"] as String,
      updatedAt: json["updated_at"] as String?,
    );
  }
}

class TasksResponse {
  final List<TaskItem> tasks;

  const TasksResponse({required this.tasks});

  factory TasksResponse.fromJson(Map<String, dynamic> json) {
    return TasksResponse(
      tasks: (json["tasks"] as List<dynamic>?)?.map((e) => TaskItem.fromJson(e as Map<String, dynamic>)).toList() ??
          const [],
    );
  }
}

class ValidationError {
  final List<Object> loc;
  final String msg;
  final String type;

  const ValidationError({required this.loc, required this.msg, required this.type});

  factory ValidationError.fromJson(Map<String, dynamic> json) {
    return ValidationError(
      loc: (json["loc"] as List<dynamic>?)?.map((e) => e as Object).toList() ?? const [],
      msg: json["msg"] as String,
      type: json["type"] as String,
    );
  }
}
